// Repository interface contract - return components for valid learning space
var mockRepo = new Mock<ILearningComponentRepository>();
var components = new List<LearningComponent> 
{ 
    new LearningComponent(1, "LS-001", 2.0f, 1.5f, 0.5f, 1.0f, 0.0f, 3.0f, "North")
};

mockRepo.Setup(r => r.GetByLearningSpaceIdAsync("LS-001"))
        .ReturnsAsync(components);

var result = await mockRepo.Object.GetByLearningSpaceIdAsync("LS-001");

Assert.That(result, Is.Not.Null);
Assert.That(result.Count(), Is.EqualTo(1));

// Verify LearningComponent can be constructed with different valid orientations
var northComponent = new LearningComponent(1, "LS-001", 2.0f, 1.5f, 0.5f, 1.0f, 0.0f, 3.0f, "North");
var southComponent = new LearningComponent(2, "LS-001", 2.0f, 1.5f, 0.5f, 1.0f, 0.0f, 3.0f, "South");

Assert.That(northComponent.Orientation, Is.EqualTo("North"));
Assert.That(southComponent.Orientation, Is.EqualTo("South"));

// Service returns list of components when learning space has components
var mockRepo = new Mock<ILearningComponentRepository>();
var components = new List<LearningComponent> 
{ 
    new LearningComponent(1, "LS-001", 2.0f, 1.5f, 0.5f, 1.0f, 0.0f, 3.0f, "North"),
    new LearningComponent(2, "LS-001", 3.0f, 2.0f, 0.3f, 2.0f, 1.0f, 4.0f, "South")
};

mockRepo.Setup(r => r.GetByLearningSpaceIdAsync("LS-001"))
        .ReturnsAsync(components);

var service = new LearningComponentService(mockRepo.Object);
var result = await service.GetComponentsByLearningSpaceIdAsync("LS-001");

Assert.That(result, Is.Not.Null);
Assert.That(result.Count(), Is.EqualTo(2));

// Service returns empty list when learning space has no components
var mockRepo = new Mock<ILearningComponentRepository>();
var emptyComponents = new List<LearningComponent>();

mockRepo.Setup(r => r.GetByLearningSpaceIdAsync("LS-002"))
        .ReturnsAsync(emptyComponents);

var service = new LearningComponentService(mockRepo.Object);
var result = await service.GetComponentsByLearningSpaceIdAsync("LS-002");

Assert.That(result, Is.Not.Null);
Assert.That(result.Count(), Is.EqualTo(0));

// Service throws exception when learning space ID is null
