var service = new LearningComponentService(mockRepo.Object);

Assert.ThrowsAsync<ArgumentNullException>(
    async () => await service.GetComponentsByLearningSpaceIdAsync(null)
);

// Service throws exception when learning space ID is empty string
var mockRepo = new Mock<ILearningComponentRepository>();
var service = new LearningComponentService(mockRepo.Object);

Assert.ThrowsAsync<ArgumentException>(
    async () => await service.GetComponentsByLearningSpaceIdAsync("")
);

// Service calls repository with correct learning space ID
var mockRepo = new Mock<ILearningComponentRepository>();
var components = new List<LearningComponent>();

mockRepo.Setup(r => r.GetByLearningSpaceIdAsync("LS-001"))
        .ReturnsAsync(components);

var service = new LearningComponentService(mockRepo.Object);
await service.GetComponentsByLearningSpaceIdAsync("LS-001");

mockRepo.Verify(r => r.GetByLearningSpaceIdAsync("LS-001"), Times.Once);

// Repository returns components for valid learning space ID
var options = new DbContextOptionsBuilder<UCRDatabaseContext>()
    .UseInMemoryDatabase(databaseName: "TestDb_GetComponents")
    .Options;

using var context = new UCRDatabaseContext(options);

var component1 = new LearningComponent(1, "LS-001", 2.0f, 1.5f, 0.5f, 1.0f, 0.0f, 3.0f, "North");
var component2 = new LearningComponent(2, "LS-001", 3.0f, 2.0f, 0.3f, 2.0f, 1.0f, 4.0f, "South");
context.LearningComponents.AddRange(component1, component2);
await context.SaveChangesAsync();

var repository = new LearningComponentRepository(context);
var result = await repository.GetByLearningSpaceIdAsync("LS-001");

Assert.That(result.Count(), Is.EqualTo(2));

// Repository returns empty list when learning space has no components
var options = new DbContextOptionsBuilder<UCRDatabaseContext>()
    .UseInMemoryDatabase(databaseName: "TestDb_EmptyComponents")
    .Options;

using var context = new UCRDatabaseContext(options);

var repository = new LearningComponentRepository(context);
var result = await repository.GetByLearningSpaceIdAsync("LS-999");

Assert.That(result, Is.Not.Null);
Assert.That(result.Count(), Is.EqualTo(0));

// Repository filters components by learning space ID correctly
var options = new DbContextOptionsBuilder<UCRDatabaseContext>()
    .UseInMemoryDatabase(databaseName: "TestDb_FilterComponents")
    .Options;

using var context = new UCRDatabaseContext(options);

var component1 = new LearningComponent(1, "LS-001", 2.0f, 1.5f, 0.5f, 1.0f, 0.0f, 3.0f, "North");
var component2 = new LearningComponent(2, "LS-002", 3.0f, 2.0f, 0.3f, 2.0f, 1.0f, 4.0f, "South");
context.LearningComponents.AddRange(component1, component2);
await context.SaveChangesAsync();

var repository = new LearningComponentRepository(context);
var result = await repository.GetByLearningSpaceIdAsync("LS-001");

Assert.That(result.Count(), Is.EqualTo(1));
Assert.That(result.First().LearningSpaceId, Is.EqualTo("LS-001"));

// Handler returns OK with components when learning space has components
